	@Test
	public void warmedHubUsesBalancedCsrSlicesWithoutRangeCursors() throws Exception {
		LmdbStore sail = (LmdbStore) repository.getSail();
		warmByObject(sail);
		long scansBefore = LmdbCsrAdjacencyCache.CSR_ROOT_SCANS.get();

		try (SailDataset dataset = sail.getBackingStore().getExplicitSailSource().dataset(IsolationLevels.NONE)) {
			NativeLmdbQuerySource source = (NativeLmdbQuerySource) dataset;
			long predicateId = source.idOf(predicate);
			LmdbRootScanPartition[] partitions = source.planRootScanPartitions(-1L, predicateId, -1L, -1L, 4);
			assertThat(partitions).hasSize(4);
			assertThat(partitions).allMatch(LmdbRootScanPartition::isCsrSlice);

			List<Integer> partitionRows = new ArrayList<>(partitions.length);
			Set<String> rows = new HashSet<>();
			for (LmdbRootScanPartition partition : partitions) {
				int count = 0;
				LmdbRootScanPartition routed = partition.withMember(7).withMember(0);
				try (RecordIterator iterator = source.statements(-1L, predicateId, -1L, -1L, routed)) {
					long[] quad;
					while ((quad = iterator.next()) != null) {
						rows.add(quad[TripleIndex.SUBJ_IDX] + "|" + quad[TripleIndex.OBJ_IDX]);
						count++;
					}
				}
				partitionRows.add(count);
			}

			assertThat(partitionRows).containsExactly(16, 16, 16, 16);
			assertThat(rows).hasSize(64);
			assertThat(LmdbCsrAdjacencyCache.CSR_ROOT_SCANS.get() - scansBefore)
					.as("every partition must use the in-heap CSR iterator instead of an LMDB range cursor")
					.isEqualTo(partitions.length);
		}
	}

	private void warmByObject(LmdbStore sail) throws Exception {
		long buildsBefore = LmdbCsrAdjacencyCache.BUILDS.get();
		try (SailDataset dataset = sail.getBackingStore().getExplicitSailSource().dataset(IsolationLevels.NONE)) {
			NativeLmdbQuerySource source = (NativeLmdbQuerySource) dataset;
			long predicateId = source.idOf(predicate);
			long[] objectIds = new long[objects.size()];
			for (int i = 0; i < objects.size(); i++) {
				objectIds[i] = source.idOf(objects.get(i));
			}
			try (NativeLmdbQuerySource.NativeProbe probe = source.newProbe()) {
				for (int round = 0; round < 64; round++) {
					for (long objectId : objectIds) {
						RecordIterator matches = probe.open(-1L, predicateId, objectId, -1L);
						while (matches.next() != null) {
							// Exhaust the retained probe before re-aiming it.
						}
					}
				}
			}
		}
		assertThat(LmdbCsrAdjacencyCache.BUILDS.get()).isGreaterThan(buildsBefore);
	}
